    def _match(self, *types: TokenType) -> Token | None:
        return self.stream.match(*types)

    def _expect(self, token_type: TokenType) -> Token:
        tok = self._current()
        if tok.type == token_type:
            return self._advance()
        raise self._error(tok, f"Expected {token_type.name}, got {tok.type.name} ({tok.value!r})")

    def _error(self, tok: Token, message: str) -> ParserError:
        return ParserError(f"Parser error at L{tok.line}:{tok.col}: {message}")


def parse(query: str) -> Node:
    """Parse a query string into an AST statement node."""
    return Parser(query).parse_statement()
